const OPENAI_API_KEY = "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";

// 🔹 BLOG
export async function generateBlog(title) {
  const res = await fetch("https://api.openai.com/v1/chat/completions", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${OPENAI_API_KEY}`,
    },
    body: JSON.stringify({
      model: "gpt-4o-mini",
      messages: [
        { role: "system", content: "Write a blog post (300-500 words)" },
        { role: "user", content: title },
      ],
    }),
  });

  const data = await res.json();
  return data.choices?.[0]?.message?.content || "";
}

// 🔹 TAGS
export async function generateTags(title, content) {
  try {
    const res = await fetch("https://api.openai.com/v1/chat/completions", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${OPENAI_API_KEY}`,
      },
      body: JSON.stringify({
        model: "gpt-4o-mini",
        messages: [
          {
            role: "system",
            content:
              "Return 5 tags as JSON array like [\"tag1\",\"tag2\"]",
          },
          {
            role: "user",
            content: `${title}\n${content}`,
          },
        ],
      }),
    });

    const data = await res.json();
    return JSON.parse(data.choices[0].message.content);
  } catch {
    return ["blog", "content"];
  }
}

// 🔹 WRITING ANALYSIS
export async function analyzeWriting(title, content) {
  return {
    score: 8,
    tone: "Professional",
    readability: "Medium",
    strengths: ["Clear topic"],
    improvements: ["Add examples"],
    rewrittenIntro: `This article explores ${title}`,
  };
}

// 🔥 ADD THESE BACK (FIX YOUR ERROR)

// 🔹 SUMMARY
export async function generateSummary(title, content) {
  return content.slice(0, 120) + "...";
}

// 🔹 SENTIMENT
export async function analyzeCommentSentiment(text) {
  return {
    sentiment: "Positive",
    score: 0.8,
  };
}

// 🔹 RECOMMENDATIONS
export async function getRecommendations(history, posts) {
  return posts.slice(0, 3);
}
